import re
from vex_sdk import verify

def validate_cve_advisory(response):
    cve_pattern = r'CVE-\d{4}-\d{4,7}'
    cves = re.findall(cve_pattern, str(response))

    verified = verify(
        response,
        schema={
            'type': 'object',
            'properties': {
                'cve_id': {'pattern': cve_pattern},
                'verified': {'const': True}
            }
        },
        external_check='cve_database_lookup'
    )
    return verified

advisory = stack.invoke('generate_advisory', {'vuln': 'buffer_overflow'})
